+<template>
+  <div class="qa-container">
+    <h3>智能问答</h3>
+    <div class="qa-content">
+      <!-- 问答历史显示（完善后，实时展示提问和回答） -->
+      <div class="qa-history">
+        <p v-if="!ragStore.qaHistory.length && !loading">上传文档后，可在此提问...</p>
+        <!-- 加载状态提示（优化交互，避免用户困惑） -->
+        <p class="loading" v-if="loading">正在生成回答，请稍候...</p>
+        <!-- 问答记录项（区分用户提问和大模型回答，样式清晰） -->
+        <div class="qa-item" v-for="(item, index) in ragStore.qaHistory" :key="index">
+          <div class="question-item">
+            <span class="role">我：</span>
+            <span class="content">{{ item.question }}</span>
+          </div>
+          <div class="answer-item">
+            <span class="role">AI：</span>
+            <span class="content">{{ item.answer }}</span>
+          </div>
+        </div>
+      </div>
+
+      <!-- 提问输入框与发送按钮（完善交互，支持回车发送） -->
+      <div class="qa-input">
+        <input type="text" class="input" v-model="question" placeholder="请输入你的问题..." @keyup.enter="handleAsk"
+          :disabled="loading"> <!-- 加载时禁用输入，避免重复提交 -->
+        />
+        <button class="btn" @click="handleAsk" :disabled="loading">提问</button>
+      </div>
+    </div>
+</template>
+
+<script setup>
+import { ref } from 'vue'
+import { useRagStore } from '../store/ragStore'
+// 引入已封装的大模型调用函数（Day4已创建llmUtils.js）
+import { callTongyiModel } from "../utils/llmUtils.js";
+
+const ragStore = useRagStore()
+const question = ref('') // 存储用户输入的提问内容
+const loading = ref(false) // 加载状态，优化用户体验
+
+// 提问逻辑（完善后，调用大模型+同步历史记录）
+const handleAsk = async () => {
+  // 校验提问内容，避免空提问
+  if (!question.value.trim()) {
+    alert('请输入问题！')
+    return
+  }
+
+  // 显示加载状态，禁用按钮和输入框
+  loading.value = true;
+  try {
+    // 调用大模型函数，传入用户提问，获取回答（Day4封装的callTongyiModel）
+    const answer = await callTongyiModel(question.value);
+
+    // 若获取到有效回答，同步到Pinia仓库（调用addQaHistory方法）
+    if (answer) {
+      ragStore.addQaHistory(question.value, answer);
+    }
+  } catch (error) {
+    // 兜底错误提示，避免程序崩溃
+    console.error("问答交互失败：", error);
+    alert("问答失败，请稍后再试！");
+  } finally {
+    // 无论成功失败，都关闭加载状态，重置输入框
+    loading.value = false;
+    question.value = '';
+  }
+}
+</script>
+
+<style scoped>
+/* 问答内容区域样式，区分提问和回答，提升可读性 */
+.qa-content {
+  display: flex;
+  flex-direction: column;
+  gap: 20px;
+  height: calc(100vh - 280px);
+  overflow-y: auto;
+}
+
+/* 问答历史容器样式 */
+.qa-history {
+  flex: 1;
+  display: flex;
+  flex-direction: column;
+  gap: 15px;
+  padding: 10px;
+}
+
+/* 加载状态样式 */
+.loading {
+  color: #42b983;
+  font-size: 14px;
+  text-align: center;
+  padding: 10px;
+}
+
+/* 单个问答项样式 */
+.qa-item {
+  display: flex;
+  flex-direction: column;
+  gap: 8px;
+  padding: 10px;
+  background: #f9f9f9;
+  border-radius: 6px;
+}
+
+/* 角色标识样式（区分用户和AI） */
+.role {
+  font-weight: bold;
+  margin-right: 8px;
+}
+
+.question-item .role {
+  color: #42b983;
+}
+
+.answer-item .role {
+  color: #646cff;
+}
+
+/* 问答内容样式 */
+.content {
+  font-size: 14px;
+  line-height: 1.5;
+  color: #333;
+}
+
+/* 提问输入区样式 */
+.qa-input {
+  display: flex;
+  gap: 10px;
+  align-items: center;
+}
+
+.qa-input .input {
+  margin-top: 0;
+  flex: 1;
+}
+
+.qa-input .btn:disabled {
+  background: #999;
+  cursor: not-allowed;
+}
+</style>
